  <svg viewBox="0 0 700 300" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="26" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">ディフィカルティ・リボン圧縮シグナル・タイムライン (2018〜2026)</text>
    <circle cx="30" cy="48" r="6" fill="#4ade80"/><text x="42" y="52" fill="#d4d4d8" font-size="13">底値的中</text>
    <circle cx="130" cy="48" r="6" fill="#fbbf24"/><text x="142" y="52" fill="#d4d4d8" font-size="13">圧縮したが底ではない</text>
    <circle cx="330" cy="48" r="6" fill="#60a5fa"/><text x="342" y="52" fill="#d4d4d8" font-size="13">前提が揺らぐ局面</text>
    <line x1="50" y1="190" x2="660" y2="190" stroke="#3f3f46" stroke-width="1.5"/>
